1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE = 25;
3	const BLOCK_OF_THREE_BASE = 60;
4	
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
16	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	};
24	
25	const INSURANCE_VALUES: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	type Item = {
37	  type: string;
38	  material?: string;
39	  enchantment?: number;
40	  cursed?: boolean;
41	};
42	type QuoteStep = { op: "quote"; items: Item[] };
43	type Damage = { itemType: string; amount: number };
44	type Incident = { cause: string; damages: Damage[] };
45	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
46	type Step = QuoteStep | ClaimStep;
47	type Customer = { yearsWithMHPCO: number };
48	type Scenario = { customer: Customer; steps: Step[] };
49	type QuoteResult = { premium: number };
50	type ClaimResult = { payout: number; remainingCap: number };
51	type StepResult = QuoteResult | ClaimResult;
52	type ScenarioResult = { results: StepResult[] };
53	
54	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
55	
56	const isKnownType = (item: Item): boolean =>
57	  item.type in BASE_PREMIUMS || COMPONENT_TYPES.has(item.type);
58	
59	const validateItems = (items: Item[]): void => {
60	  for (const item of items) {
61	    if (!isKnownType(item)) {
62	      throw new Error(`Unknown item type: ${item.type}`);
63	    }
64	  }
65	};
66	
67	const countByType = (items: Item[]): Map<string, number> => {
68	  const counts = new Map<string, number>();
69	  for (const item of items) {
70	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
71	  }
72	  return counts;
73	};
74	
75	const componentTypeBase = (count: number): number =>
76	  count === 3 ? BLOCK_OF_THREE_BASE : count * COMPONENT_BASE;
77	
78	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
79	
80	const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
81	
82	const mainItemSurcharge = (item: Item): number => {
83	  const base = mainItemBase(item);
84	  const cursed = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
85	  const highEnch =
86	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
87	  return cursed + highEnch;
88	};
89	
90	const mainItemsBase = (mainItems: Item[]): number => sum(mainItems.map(mainItemBase));
91	
92	const componentsBase = (components: Item[]): number => {
93	  const counts = countByType(components);
94	  return sum([...counts.values()].map(componentTypeBase));
95	};
96	
97	const itemSurcharges = (mainItems: Item[]): number => sum(mainItems.map(mainItemSurcharge));
98	
99	const policyBase = (mainItems: Item[], components: Item[]): number =>
100	  mainItemsBase(mainItems) + componentsBase(components);
101	
102	const loyaltyDiscount = (base: number, customer: Customer): number =>
103	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? base * LOYALTY_DISCOUNT_RATE : 0;
104	
105	const insuranceSum = (items: Item[]): number =>
106	  sum(items.map((item) => INSURANCE_VALUES[item.type] ?? 0));
107	
108	type Policy = { items: Item[]; cap: number };
109	
110	const quote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { result: QuoteResult; policy: Policy } => {
111	  validateItems(step.items);
112	  const mainItems = step.items.filter((item) => !isComponent(item));
113	  const components = step.items.filter(isComponent);
114	  const base = policyBase(mainItems, components);
115	  const surcharges = itemSurcharges(mainItems);
116	  const firstInsurance = base * FIRST_INSURANCE_RATE;
117	  const loyalty = loyaltyDiscount(base, customer);
118	  const followUp = isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
119	  const premium = Math.ceil(base + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
120	  const cap = insuranceSum(step.items) * CAP_MULTIPLIER;
121	  return { result: { premium }, policy: { items: step.items, cap } };
122	};
123	
124	const damagePayout = (damage: Damage, policy: Policy): number => {
125	  const item = policy.items.find((i) => i.type === damage.itemType);
126	  const reimbursable =
127	    item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
128	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
129	      : damage.amount;
130	  return reimbursable - DEDUCTIBLE;
131	};
132	
133	const claim = (step: ClaimStep, policy: Policy): ClaimResult => {
134	  const totalPayout = sum(step.incident.damages.map((d) => damagePayout(d, policy)));
135	  return { payout: totalPayout, remainingCap: policy.cap - totalPayout };
136	};
137	
138	export const runScenario = (scenario: Scenario): ScenarioResult => {
139	  const policies: Policy[] = [];
140	  const results: StepResult[] = [];
141	  for (const step of scenario.steps) {
142	    if (step.op === "quote") {
143	      const isFollowUp = policies.length > 0;
144	      const { result, policy } = quote(step, scenario.customer, isFollowUp);
145	      policies.push(policy);
146	      results.push(result);
147	    } else {
148	      results.push(claim(step, policies[step.policy]));
149	    }
150	  }
151	  return { results };
152	};
